  `updated_at` datetime(6) DEFAULT NULL,
  `user_uid` varchar(255) DEFAULT NULL,
  `version` int NOT NULL,
  `avatar` varchar(255) DEFAULT NULL,
  `category_uid` varchar(255) DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  `is_kb_enabled` bit(1) DEFAULT NULL,
  `is_kb_source_enabled` bit(1) DEFAULT NULL,
  `kb_uid` varchar(255) DEFAULT NULL,
  `is_audio_enabled` bit(1) DEFAULT NULL,
  `llm_audio_model` varchar(255) DEFAULT NULL,
  `llm_audio_provider` varchar(255) DEFAULT NULL,
  `llm_audio_provider_uid` varchar(255) DEFAULT NULL,
  `llm_context_msg_count` int DEFAULT NULL,
  `default_reply` varchar(255) DEFAULT NULL,
  `llm_do_sample` bit(1) DEFAULT NULL,
  `is_search_enabled` bit(1) DEFAULT NULL,
  `is_streaming_enabled` bit(1) DEFAULT NULL,
  `is_thinking_enabled` bit(1) DEFAULT NULL,
  `is_llm_enabled` bit(1) DEFAULT NULL,
  `llm_max_tokens` int DEFAULT NULL,
  `llm_prompt` text,
  `llm_request_id` varchar(255) DEFAULT NULL,
  `is_rerank_enabled` bit(1) DEFAULT NULL,
  `llm_rerank_model` varchar(255) DEFAULT NULL,
  `llm_rerank_provider` varchar(255) DEFAULT NULL,
  `llm_rerank_provider_uid` varchar(255) DEFAULT NULL,
  `llm_response_format` varchar(255) DEFAULT NULL,
  `llm_rewrite_enabled` bit(1) DEFAULT NULL,
  `llm_rewrite_model` varchar(255) DEFAULT NULL,
  `llm_rewrite_prompt` text,
  `llm_rewrite_provider` varchar(255) DEFAULT NULL,
  `llm_rewrite_provider_uid` varchar(255) DEFAULT NULL,
  `llm_score_threshold` double DEFAULT NULL,
  `llm_search_type` varchar(255) DEFAULT NULL,
  `llm_stops` varbinary(255) DEFAULT NULL,
  `llm_temperature` double DEFAULT NULL,
  `llm_text_model` varchar(255) DEFAULT NULL,
  `llm_text_provider` varchar(255) DEFAULT NULL,
  `llm_text_provider_uid` varchar(255) DEFAULT NULL,
  `llm_tool_choice` varchar(255) DEFAULT NULL,
  `llm_tools` varbinary(255) DEFAULT NULL,
  `llm_top_k` int DEFAULT NULL,
  `llm_top_p` double DEFAULT NULL,
  `llm_use_when_kb_empty` bit(1) DEFAULT NULL,
  `llm_user_id` varchar(255) DEFAULT NULL,
  `name` varchar(255) DEFAULT NULL,
  `nickname` varchar(255) DEFAULT NULL,
  `is_system` bit(1) DEFAULT NULL,
  `robot_type` varchar(255) DEFAULT NULL,
  `settings_id` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UKdjcymlcaaf9rn72upjsxwekun` (`uuid`),
  KEY `FKodsdvx4b4lqpbunimy05gbpff` (`settings_id`),
  CONSTRAINT `FKodsdvx4b4lqpbunimy05gbpff` FOREIGN KEY (`settings_id`) REFERENCES `bytedesk_ai_robot_settings` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

