INSERT INTO `bytedesk_ai_robot` (`id`, `created_at`, `is_deleted`, `level_type`, `org_uid`, `platform_type`, `uuid`, `updated_at`, `user_uid`, `version`, `avatar`, `category_uid`, `description`, `is_kb_enabled`, `is_kb_source_enabled`, `kb_uid`, `is_audio_enabled`, `llm_audio_model`, `llm_audio_provider`, `llm_audio_provider_uid`, `llm_context_msg_count`, `default_reply`, `llm_do_sample`, `is_search_enabled`, `is_streaming_enabled`, `is_thinking_enabled`, `is_llm_enabled`, `llm_max_tokens`, `llm_prompt`, `llm_request_id`, `is_rerank_enabled`, `llm_rerank_model`, `llm_rerank_provider`, `llm_rerank_provider_uid`, `llm_response_format`, `llm_rewrite_enabled`, `llm_rewrite_model`, `llm_rewrite_prompt`, `llm_rewrite_provider`, `llm_rewrite_provider_uid`, `llm_score_threshold`, `llm_search_type`, `llm_stops`, `llm_temperature`, `llm_text_model`, `llm_text_provider`, `llm_text_provider_uid`, `llm_tool_choice`, `llm_tools`, `llm_top_k`, `llm_top_p`, `llm_use_when_kb_empty`, `llm_user_id`, `name`, `nickname`, `is_system`, `robot_type`, `settings_id`)
VALUES
	(1,'2026-03-05 04:42:13.249482',b'0','PLATFORM','','BYTEDESK','1863057265393846','2026-03-05 04:42:13.249482',NULL,0,'http://127.0.0.1:9003/avatars/robot.png','1863057265393805','创建一个空白智能体，不设置默认prompt，不设置默认角色。',b'0',b'1',NULL,b'0','qwen3-tts-instruct-flash-realtime','dashscope',NULL,0,'抱歉，我暂时无法回答这个问题。',b'1',b'0',b'0',b'1',b'1',1024,'请回答用户提出的问题',NULL,b'0','qwen3-rerank','dashscope',NULL,'text',b'0','qwen3-max','你是一个专注于指代消解和省略补全的智能助手，你的任务是根据历史对话上下文，清晰识别用户问题中的代词并替换为明确的主语，同时补全省略的关键信息。\n\n## 改写目标\n请根据历史对话，对当前用户问题进行改写，目标是：\n- 进行指代消解，将\"它\"、\"这个\"、\"那个\"、\"他\"、\"她\"、\"它们\"、\"他们\"、\"她们\"等代词替换为明确的主语\n- 补全省略的关键信息，确保问题语义完整\n- 保持问题的原始含义和表达方式不变\n- 改写后必须也是一个问题\n- 改写后的问题字数控制在30字以内\n- 仅输出改写后的问题，不要输出任何解释，更不要尝试回答该问题，后面有其他助手回去解答此问题\n\n## Few-shot示例\n\n示例1:\n历史对话:\n用户: 微信支付有哪些功能？\n助手: 微信支付的主要功能包括转账、付款码、收款、信用卡还款等多种支付服务。\n\n用户问题: 它的安全性\n改写后: 微信支付的安全性\n\n示例2:\n历史对话:\n用户: 苹果手机电池不耐用怎么办？\n助手: 您可以通过降低屏幕亮度、关闭后台应用和定期更新系统来延长电池寿命。\n\n用户问题: 这样会影响使用体验吗？\n改写后: 降低屏幕亮度和关闭后台应用是否影响使用体验\n\n示例3:\n历史对话:\n用户: 如何制作红烧肉？\n助手: 红烧肉的制作需要先将肉块焯水，然后加入酱油、糖等调料慢炖。\n\n用户问题: 需要炖多久？\n改写后: 红烧肉需要炖多久\n\n示例4:\n历史对话:\n用户: 北京到上海的高铁票价是多少？\n助手: 北京到上海的高铁票价根据车次和座位类型不同，二等座约为553元，一等座约为933元。\n\n用户问题: 时间呢？\n改写后: 北京到上海的高铁时长\n\n示例5:\n历史对话:\n用户: 如何注册微信账号？\n助手: 注册微信账号需要下载微信APP，输入手机号，接收验证码，然后设置昵称和密码。\n\n用户问题: 国外手机号可以吗？\n改写后: 国外手机号是否可以注册微信账号\n','dashscope',NULL,0.5,'FULLTEXT',X'ACED0005737200136A6176612E7574696C2E41727261794C6973747881D21D99C7619D03000149000473697A6578700000000077040000000078',0,'qwen3-max','dashscope',NULL,'auto',X'ACED0005737200136A6176612E7574696C2E41727261794C6973747881D21D99C7619D03000149000473697A6578700000000077040000000078',3,0.7,b'1',NULL,'void_agent','创建空白智能体 - void agent',b'1','LLM',1),
