INSERT INTO `bytedesk_kbase_faq` (`id`, `created_at`, `is_deleted`, `level_type`, `org_uid`, `platform_type`, `uuid`, `updated_at`, `user_uid`, `version`, `answer`, `answer_html`, `answer_list`, `answer_markdown`, `attachments`, `category_uid`, `click_count`, `doc_id_list`, `down_count`, `elastic_status`, `is_enabled`, `end_date`, `feedback_count`, `file_uid`, `images`, `question`, `similar_questions`, `start_date`, `tag_list`, `transfer_count`, `faq_type`, `up_count`, `vector_status`, `view_count`, `kbase_id`)
VALUES
	(1,'2026-03-05 04:42:10.450406',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_faq_001','2026-03-05 04:42:10.450406',NULL,0,'微语支持丰富的即时通讯功能，包括：1. 单聊功能：支持文本、图片、语音、视频、文件等多种消息类型，具有@提醒、消息撤回、已读回执等功能；2. 群聊功能：支持群组创建、解散、设置、公告、群头像等管理功能，以及成员邀请、移除、禁言等权限管理。',NULL,'[]',NULL,'',NULL,0,'',0,'NEW',b'1','2126-03-05 04:42:10.442033',0,NULL,'','微语支持哪些基本的即时通讯功能？','','2026-03-05 04:42:10.442026','',0,'TEXT',0,'NEW',0,3),
	(2,'2026-03-05 04:42:10.471138',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_faq_002','2026-03-05 04:42:10.471138',NULL,0,'使用Docker部署微语系统非常简单，只需要两步：1. 克隆项目并启动：执行命令 \'git clone https://github.com/Bytedesk/bytedesk.git && cd bytedesk/deploy/docker && ./start.sh mysql artemis standard all\'；2. 修改配置文件中的服务器IP，将deploy/docker/compose-app-bytedesk.yaml中的127.0.0.1替换为你的服务器IP，主要是BYTEDESK_UPLOAD_URL和BYTEDESK_KBASE_API_URL这两个配置项。',NULL,'[]',NULL,'',NULL,0,'',0,'NEW',b'1','2126-03-05 04:42:10.464899',0,NULL,'','如何快速使用Docker部署微语系统？','','2026-03-05 04:42:10.464897','',0,'TEXT',0,'NEW',0,3),
	(3,'2026-03-05 04:42:10.481678',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_faq_003','2026-03-05 04:42:10.481678',NULL,0,'微语的在线客服模块包含三种服务模式：1. agent模式：提供一对一人工客服服务，不支持机器人接待；2. robot模式：提供机器人客服服务，不支持转人工；3. workgroup模式：工作组模式，支持机器人接待，并且支持转人工服务。此外还包括客服管理、会话管理、消息管理、访客管理、自动化功能、统计分析等功能。',NULL,'[]',NULL,'',NULL,0,'',0,'NEW',b'1','2126-03-05 04:42:10.475655',0,NULL,'','微语的在线客服模块包含哪些主要功能？','','2026-03-05 04:42:10.475653','',0,'TEXT',0,'NEW',0,3);

