	(4,'2026-03-05 04:42:17.002086',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_leaveApprovalProcess','2026-03-05 04:42:17.077039',NULL,1,'b008a17a-184d-11f1-9a31-e2a00dfcd8a4','请假审批流程','请假审批流程','<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\"\n             xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\n             xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\"\n             xmlns:flowable=\"http://flowable.org/bpmn\"\n             xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\"\n             xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\"\n             xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\"\n             typeLanguage=\"http://www.w3.org/2001/XMLSchema\"\n             expressionLanguage=\"http://www.w3.org/1999/XPath\"\n             targetNamespace=\"BytedeskLeaveApproval\">\n  <process id=\"leaveApprovalProcess\" name=\"请假审批流程\" isExecutable=\"true\">\n    <extensionElements>\n      <flowable:executionListener event=\"start\" delegateExpression=\"${demoExecutionListener}\"/>\n      <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n    </extensionElements>\n\n    <!-- 开始事件 -->\n    <startEvent id=\"start\" name=\"提交申请\"/>\n\n    <!-- 提交请假申请 -->\n    <userTask id=\"submitLeave\" name=\"填写请假申请\" flowable:assignee=\"${applicantUid}\">\n      <documentation>员工填写请假申请，包括请假类型、开始时间、结束时间、请假事由</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow1\" sourceRef=\"start\" targetRef=\"submitLeave\"/>\n\n    <!-- 判断请假天数网关 -->\n    <exclusiveGateway id=\"checkDaysGateway\" name=\"判断请假天数\"/>\n\n    <sequenceFlow id=\"flow2\" sourceRef=\"submitLeave\" targetRef=\"checkDaysGateway\"/>\n\n    <!-- 短期请假：直接主管审批 -->\n    <sequenceFlow id=\"flowShortLeave\" name=\"短期请假（≤3天）\" sourceRef=\"checkDaysGateway\" targetRef=\"supervisorApproval\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${leaveDays &lt;= 3}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"supervisorApproval\" name=\"主管审批\" flowable:candidateGroups=\"${supervisorGroupId}\">\n      <documentation>直接主管审批请假申请</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 主管审批结果网关 -->\n    <exclusiveGateway id=\"supervisorResultGateway\" name=\"主管审批结果\"/>\n\n    <sequenceFlow id=\"flow3\" sourceRef=\"supervisorApproval\" targetRef=\"supervisorResultGateway\"/>\n\n    <!-- 主管批准，进入结束 -->\n    <sequenceFlow id=\"flowSupervisorApproved\" name=\"批准\" sourceRef=\"supervisorResultGateway\" targetRef=\"end\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${supervisorApproved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 主管拒绝，结束 -->\n    <sequenceFlow id=\"flowSupervisorRejected\" name=\"拒绝\" sourceRef=\"supervisorResultGateway\" targetRef=\"rejectEnd\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${supervisorApproved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 长期请假：部门经理审批 -->\n    <sequenceFlow id=\"flowLongLeave\" name=\"长期请假（>3天）\" sourceRef=\"checkDaysGateway\" targetRef=\"managerApproval\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${leaveDays &gt; 3}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"managerApproval\" name=\"部门经理审批\" flowable:candidateGroups=\"${managerGroupId}\">\n      <documentation>部门经理审批长期请假申请</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n        <!-- 审批超时定时器：2天 -->\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskTimeoutListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 经理审批超时定时器 -->\n    <boundaryEvent id=\"managerTimeout\" cancelActivity=\"false\" attachedToRef=\"managerApproval\">\n      <timerEventDefinition>\n        <timeDuration>P2D</timeDuration>\n      </timerEventDefinition>\n    </boundaryEvent>\n\n    <serviceTask id=\"managerTimeoutNotify\" name=\"超时提醒\" flowable:delegateExpression=\"${demoTimeoutNotifyDelegate}\"/>\n\n    <sequenceFlow id=\"flowManagerTimeout\" sourceRef=\"managerTimeout\" targetRef=\"managerTimeoutNotify\"/>\n\n    <sequenceFlow id=\"flowManagerTimeoutNotify\" sourceRef=\"managerTimeoutNotify\" targetRef=\"managerApproval\"/>\n\n    <!-- 经理审批结果网关 -->\n    <exclusiveGateway id=\"managerResultGateway\" name=\"经理审批结果\"/>\n\n    <sequenceFlow id=\"flow4\" sourceRef=\"managerApproval\" targetRef=\"managerResultGateway\"/>\n\n    <!-- 经理批准，需要HR备案 -->\n    <sequenceFlow id=\"flowManagerApproved\" name=\"批准\" sourceRef=\"managerResultGateway\" targetRef=\"hrRecord\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${managerApproved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 经理拒绝 -->\n    <sequenceFlow id=\"flowManagerRejected\" name=\"拒绝\" sourceRef=\"managerResultGateway\" targetRef=\"rejectEnd\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${managerApproved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- HR备案 -->\n    <userTask id=\"hrRecord\" name=\"HR备案\" flowable:candidateGroups=\"${hrGroupId}\">\n      <documentation>HR部门记录请假信息，更新考勤系统</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow5\" sourceRef=\"hrRecord\" targetRef=\"end\"/>\n\n    <!-- 正常结束事件 -->\n    <endEvent id=\"end\" name=\"批准结束\"/>\n\n    <!-- 拒绝结束事件 -->\n    <endEvent id=\"rejectEnd\" name=\"拒绝结束\"/>\n  </process>\n\n  <!-- 流程图布局 -->\n  <bpmndi:BPMNDiagram id=\"BPMNDiagram_leaveApprovalProcess\">\n      <bpmndi:BPMNPlane bpmnElement=\"leaveApprovalProcess\" id=\"BPMNPlane_leaveApprovalProcess\">\n        <bpmndi:BPMNShape bpmnElement=\"start\" id=\"BPMNShape_start\">\n          <omgdc:Bounds height=\"30.0\" width=\"30.0\" x=\"100.0\" y=\"200.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"submitLeave\" id=\"BPMNShape_submitLeave\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"180.0\" y=\"185.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"checkDaysGateway\" id=\"BPMNShape_checkDaysGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"330.0\" y=\"195.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"supervisorApproval\" id=\"BPMNShape_supervisorApproval\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"80.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerApproval\" id=\"BPMNShape_managerApproval\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"280.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"supervisorResultGateway\" id=\"BPMNShape_supervisorResultGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"580.0\" y=\"90.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerResultGateway\" id=\"BPMNShape_managerResultGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"580.0\" y=\"290.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"hrRecord\" id=\"BPMNShape_hrRecord\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"700.0\" y=\"280.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"end\" id=\"BPMNShape_end\">\n          <omgdc:Bounds height=\"28.0\" width=\"28.0\" x=\"850.0\" y=\"296.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"rejectEnd\" id=\"BPMNShape_rejectEnd\">\n          <omgdc:Bounds height=\"28.0\" width=\"28.0\" x=\"750.0\" y=\"96.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerTimeout\" id=\"BPMNShape_managerTimeout\">\n          <omgdc:Bounds height=\"30.0\" width=\"30.0\" x=\"465.0\" y=\"340.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerTimeoutNotify\" id=\"BPMNShape_managerTimeoutNotify\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"560.0\" y=\"390.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNEdge bpmnElement=\"flow1\" id=\"BPMNEdge_flow1\">\n          <omgdi:waypoint x=\"129.949998\" y=\"215.0\"/>\n          <omgdi:waypoint x=\"180.0\" y=\"215.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow2\" id=\"BPMNEdge_flow2\">\n          <omgdi:waypoint x=\"280.0\" y=\"215.0\"/>\n          <omgdi:waypoint x=\"330.0\" y=\"215.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowShortLeave\" id=\"BPMNEdge_flowShortLeave\">\n          <omgdi:waypoint x=\"350.0\" y=\"195.0\"/>\n          <omgdi:waypoint x=\"350.0\" y=\"110.0\"/>\n          <omgdi:waypoint x=\"430.0\" y=\"110.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowLongLeave\" id=\"BPMNEdge_flowLongLeave\">\n          <omgdi:waypoint x=\"350.0\" y=\"235.0\"/>\n          <omgdi:waypoint x=\"350.0\" y=\"310.0\"/>\n          <omgdi:waypoint x=\"430.0\" y=\"310.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow3\" id=\"BPMNEdge_flow3\">\n          <omgdi:waypoint x=\"530.0\" y=\"110.0\"/>\n          <omgdi:waypoint x=\"580.0\" y=\"110.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowSupervisorApproved\" id=\"BPMNEdge_flowSupervisorApproved\">\n          <omgdi:waypoint x=\"620.0\" y=\"110.0\"/>\n          <omgdi:waypoint x=\"865.0\" y=\"110.0\"/>\n          <omgdi:waypoint x=\"865.0\" y=\"296.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowSupervisorRejected\" id=\"BPMNEdge_flowSupervisorRejected\">\n          <omgdi:waypoint x=\"600.0\" y=\"130.0\"/>\n          <omgdi:waypoint x=\"600.0\" y=\"180.0\"/>\n          <omgdi:waypoint x=\"764.0\" y=\"180.0\"/>\n          <omgdi:waypoint x=\"764.0\" y=\"124.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow4\" id=\"BPMNEdge_flow4\">\n          <omgdi:waypoint x=\"530.0\" y=\"310.0\"/>\n          <omgdi:waypoint x=\"580.0\" y=\"310.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerApproved\" id=\"BPMNEdge_flowManagerApproved\">\n          <omgdi:waypoint x=\"620.0\" y=\"310.0\"/>\n          <omgdi:waypoint x=\"750.0\" y=\"310.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerRejected\" id=\"BPMNEdge_flowManagerRejected\">\n          <omgdi:waypoint x=\"600.0\" y=\"330.0\"/>\n          <omgdi:waypoint x=\"600.0\" y=\"480.0\"/>\n          <omgdi:waypoint x=\"764.0\" y=\"480.0\"/>\n          <omgdi:waypoint x=\"764.0\" y=\"124.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow5\" id=\"BPMNEdge_flow5\">\n          <omgdi:waypoint x=\"800.0\" y=\"310.0\"/>\n          <omgdi:waypoint x=\"850.0\" y=\"310.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerTimeout\" id=\"BPMNEdge_flowManagerTimeout\">\n          <omgdi:waypoint x=\"495.0\" y=\"369.949998\"/>\n          <omgdi:waypoint x=\"495.0\" y=\"390.0\"/>\n          <omgdi:waypoint x=\"560.0\" y=\"390.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerTimeoutNotify\" id=\"BPMNEdge_flowManagerTimeoutNotify\">\n          <omgdi:waypoint x=\"660.0\" y=\"420.0\"/>\n          <omgdi:waypoint x=\"710.0\" y=\"420.0\"/>\n          <omgdi:waypoint x=\"710.0\" y=\"339.949998\"/>\n        </bpmndi:BPMNEdge>\n      </bpmndi:BPMNPlane>\n    </bpmndi:BPMNDiagram>\n</definitions>\n','DEPLOYED','DEMO'),
	(5,'2026-03-05 04:42:17.090163',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_reimbursementApprovalProcess','2026-03-05 04:42:17.177511',NULL,1,'b0176e8e-184d-11f1-9a31-e2a00dfcd8a4','报销审批流程','报销审批流程','<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\"\n             xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\n             xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\"\n             xmlns:flowable=\"http://flowable.org/bpmn\"\n             xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\"\n             xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\"\n             xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\"\n             typeLanguage=\"http://www.w3.org/2001/XMLSchema\"\n             expressionLanguage=\"http://www.w3.org/1999/XPath\"\n             targetNamespace=\"BytedeskReimbursement\">\n  <process id=\"reimbursementApprovalProcess\" name=\"报销审批流程\" isExecutable=\"true\">\n    <extensionElements>\n      <flowable:executionListener event=\"start\" delegateExpression=\"${demoExecutionListener}\"/>\n      <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n    </extensionElements>\n\n    <!-- 开始事件 -->\n    <startEvent id=\"start\" name=\"提交报销\"/>\n\n    <!-- 提交报销申请 -->\n    <userTask id=\"submitReimbursement\" name=\"填写报销申请\" flowable:assignee=\"${applicantUid}\">\n      <documentation>员工填写报销申请，包括报销类型、金额、发票附件</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow1\" sourceRef=\"start\" targetRef=\"submitReimbursement\"/>\n\n    <!-- 财务初审 -->\n    <userTask id=\"financeReview\" name=\"财务初审\" flowable:candidateGroups=\"${financeGroupId}\">\n      <documentation>财务人员审核报销单据的合规性</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow2\" sourceRef=\"submitReimbursement\" targetRef=\"financeReview\"/>\n\n    <!-- 财务初审结果网关 -->\n    <exclusiveGateway id=\"financeReviewGateway\" name=\"财务初审结果\"/>\n\n    <sequenceFlow id=\"flow3\" sourceRef=\"financeReview\" targetRef=\"financeReviewGateway\"/>\n\n    <!-- 初审不通过 -->\n    <sequenceFlow id=\"flowFinanceRejected\" name=\"初审不通过\" sourceRef=\"financeReviewGateway\" targetRef=\"rejectEnd\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${financeApproved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 判断报销金额网关 -->\n    <exclusiveGateway id=\"checkAmountGateway\" name=\"判断报销金额\"/>\n\n    <sequenceFlow id=\"flowFinanceApproved\" name=\"初审通过\" sourceRef=\"financeReviewGateway\" targetRef=\"checkAmountGateway\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${financeApproved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 小额报销：部门经理审批 -->\n    <sequenceFlow id=\"flowSmallAmount\" name=\"小额报销（≤5000）\" sourceRef=\"checkAmountGateway\" targetRef=\"managerApproval\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${amount &lt;= 5000}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"managerApproval\" name=\"部门经理审批\" flowable:candidateGroups=\"${managerGroupId}\">\n      <documentation>部门经理审批小额报销</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 经理审批结果网关 -->\n    <exclusiveGateway id=\"managerResultGateway\" name=\"经理审批结果\"/>\n\n    <sequenceFlow id=\"flow4\" sourceRef=\"managerApproval\" targetRef=\"managerResultGateway\"/>\n\n    <!-- 经理批准 -->\n    <sequenceFlow id=\"flowManagerApproved\" name=\"批准\" sourceRef=\"managerResultGateway\" targetRef=\"parallelFork\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${managerApproved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 经理拒绝 -->\n    <sequenceFlow id=\"flowManagerRejected\" name=\"拒绝\" sourceRef=\"managerResultGateway\" targetRef=\"rejectEnd\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${managerApproved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 大额报销：并行网关，财务总监+总经理同时审批 -->\n    <sequenceFlow id=\"flowLargeAmount\" name=\"大额报销（>5000）\" sourceRef=\"checkAmountGateway\" targetRef=\"parallelFork\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${amount &gt; 5000}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 并行网关：分叉 -->\n    <parallelGateway id=\"parallelFork\" name=\"并行审批\"/>\n\n    <!-- 财务总监审批 -->\n    <userTask id=\"cfoApproval\" name=\"财务总监审批\" flowable:candidateGroups=\"${cfoGroupId}\">\n      <documentation>财务总监审批大额报销</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow5\" sourceRef=\"parallelFork\" targetRef=\"cfoApproval\"/>\n\n    <!-- 总经理审批 -->\n    <userTask id=\"ceoApproval\" name=\"总经理审批\" flowable:candidateGroups=\"${ceoGroupId}\">\n      <documentation>总经理审批大额报销</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow6\" sourceRef=\"parallelFork\" targetRef=\"ceoApproval\"/>\n\n    <!-- 并行网关：汇聚 -->\n    <parallelGateway id=\"parallelJoin\" name=\"等待并行审批完成\"/>\n\n    <sequenceFlow id=\"flow7\" sourceRef=\"cfoApproval\" targetRef=\"parallelJoin\"/>\n\n    <sequenceFlow id=\"flow8\" sourceRef=\"ceoApproval\" targetRef=\"parallelJoin\"/>\n\n    <!-- 判断大额审批结果网关 -->\n    <exclusiveGateway id=\"largeAmountResultGateway\" name=\"大额审批结果\"/>\n\n    <sequenceFlow id=\"flow9\" sourceRef=\"parallelJoin\" targetRef=\"largeAmountResultGateway\"/>\n\n    <!-- 大额审批全部批准 -->\n    <sequenceFlow id=\"flowLargeApproved\" name=\"全部批准\" sourceRef=\"largeAmountResultGateway\" targetRef=\"paymentProcess\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${cfoApproved == true &amp;&amp; ceoApproved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 大额审批有拒绝 -->\n    <sequenceFlow id=\"flowLargeRejected\" name=\"有拒绝\" sourceRef=\"largeAmountResultGateway\" targetRef=\"rejectEnd\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${cfoApproved == false || ceoApproved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 打款处理 -->\n    <serviceTask id=\"paymentProcess\" name=\"打款处理\" flowable:delegateExpression=\"${demoPaymentDelegate}\">\n      <documentation>财务系统自动打款</documentation>\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n      </extensionElements>\n    </serviceTask>\n\n    <sequenceFlow id=\"flow10\" sourceRef=\"paymentProcess\" targetRef=\"notifyPayment\"/>\n\n    <!-- 打款通知 -->\n    <serviceTask id=\"notifyPayment\" name=\"发送打款通知\" flowable:delegateExpression=\"${demoNotificationDelegate}\">\n      <documentation>发送打款成功通知给申请人</documentation>\n    </serviceTask>\n\n    <sequenceFlow id=\"flow11\" sourceRef=\"notifyPayment\" targetRef=\"end\"/>\n\n    <!-- 正常结束事件 -->\n    <endEvent id=\"end\" name=\"流程结束\"/>\n\n    <!-- 拒绝结束事件 -->\n    <endEvent id=\"rejectEnd\" name=\"拒绝结束\"/>\n  </process>\n\n  <!-- 流程图布局 -->\n  <bpmndi:BPMNDiagram id=\"BPMNDiagram_reimbursementApprovalProcess\">\n      <bpmndi:BPMNPlane bpmnElement=\"reimbursementApprovalProcess\" id=\"BPMNPlane_reimbursementApprovalProcess\">\n        <bpmndi:BPMNShape bpmnElement=\"start\" id=\"BPMNShape_start\">\n          <omgdc:Bounds height=\"30.0\" width=\"30.0\" x=\"80.0\" y=\"300.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"submitReimbursement\" id=\"BPMNShape_submitReimbursement\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"160.0\" y=\"285.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"financeReview\" id=\"BPMNShape_financeReview\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"300.0\" y=\"285.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"financeReviewGateway\" id=\"BPMNShape_financeReviewGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"450.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"checkAmountGateway\" id=\"BPMNShape_checkAmountGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"560.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerApproval\" id=\"BPMNShape_managerApproval\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"650.0\" y=\"180.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"managerResultGateway\" id=\"BPMNShape_managerResultGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"800.0\" y=\"190.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"parallelFork\" id=\"BPMNShape_parallelFork\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"690.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"cfoApproval\" id=\"BPMNShape_cfoApproval\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"780.0\" y=\"260.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"ceoApproval\" id=\"BPMNShape_ceoApproval\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"780.0\" y=\"350.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"parallelJoin\" id=\"BPMNShape_parallelJoin\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"940.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"largeAmountResultGateway\" id=\"BPMNShape_largeAmountResultGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"1040.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"paymentProcess\" id=\"BPMNShape_paymentProcess\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"1140.0\" y=\"285.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"notifyPayment\" id=\"BPMNShape_notifyPayment\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"1280.0\" y=\"285.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"end\" id=\"BPMNShape_end\">\n          <omgdc:Bounds height=\"28.0\" width=\"28.0\" x=\"1430.0\" y=\"301.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"rejectEnd\" id=\"BPMNShape_rejectEnd\">\n          <omgdc:Bounds height=\"28.0\" width=\"28.0\" x=\"970.0\" y=\"96.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNEdge bpmnElement=\"flow1\" id=\"BPMNEdge_flow1\">\n          <omgdi:waypoint x=\"109.949998\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"160.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow2\" id=\"BPMNEdge_flow2\">\n          <omgdi:waypoint x=\"260.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"300.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow3\" id=\"BPMNEdge_flow3\">\n          <omgdi:waypoint x=\"400.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"450.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowFinanceApproved\" id=\"BPMNEdge_flowFinanceApproved\">\n          <omgdi:waypoint x=\"490.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"560.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowFinanceRejected\" id=\"BPMNEdge_flowFinanceRejected\">\n          <omgdi:waypoint x=\"470.0\" y=\"295.0\"/>\n          <omgdi:waypoint x=\"470.0\" y=\"150.0\"/>\n          <omgdi:waypoint x=\"969.0\" y=\"150.0\"/>\n          <omgdi:waypoint x=\"969.0\" y=\"124.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowSmallAmount\" id=\"BPMNEdge_flowSmallAmount\">\n          <omgdi:waypoint x=\"580.0\" y=\"295.0\"/>\n          <omgdi:waypoint x=\"580.0\" y=\"210.0\"/>\n          <omgdi:waypoint x=\"650.0\" y=\"210.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowLargeAmount\" id=\"BPMNEdge_flowLargeAmount\">\n          <omgdi:waypoint x=\"600.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"690.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow4\" id=\"BPMNEdge_flow4\">\n          <omgdi:waypoint x=\"750.0\" y=\"210.0\"/>\n          <omgdi:waypoint x=\"800.0\" y=\"210.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerApproved\" id=\"BPMNEdge_flowManagerApproved\">\n          <omgdi:waypoint x=\"840.0\" y=\"210.0\"/>\n          <omgdi:waypoint x=\"1190.0\" y=\"210.0\"/>\n          <omgdi:waypoint x=\"1190.0\" y=\"285.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowManagerRejected\" id=\"BPMNEdge_flowManagerRejected\">\n          <omgdi:waypoint x=\"820.0\" y=\"230.0\"/>\n          <omgdi:waypoint x=\"820.0\" y=\"180.0\"/>\n          <omgdi:waypoint x=\"984.0\" y=\"180.0\"/>\n          <omgdi:waypoint x=\"984.0\" y=\"124.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow5\" id=\"BPMNEdge_flow5\">\n          <omgdi:waypoint x=\"730.0\" y=\"305.0\"/>\n          <omgdi:waypoint x=\"780.0\" y=\"290.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow6\" id=\"BPMNEdge_flow6\">\n          <omgdi:waypoint x=\"730.0\" y=\"325.0\"/>\n          <omgdi:waypoint x=\"780.0\" y=\"380.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow7\" id=\"BPMNEdge_flow7\">\n          <omgdi:waypoint x=\"880.0\" y=\"290.0\"/>\n          <omgdi:waypoint x=\"960.0\" y=\"305.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow8\" id=\"BPMNEdge_flow8\">\n          <omgdi:waypoint x=\"880.0\" y=\"380.0\"/>\n          <omgdi:waypoint x=\"960.0\" y=\"325.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow9\" id=\"BPMNEdge_flow9\">\n          <omgdi:waypoint x=\"980.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"1040.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowLargeApproved\" id=\"BPMNEdge_flowLargeApproved\">\n          <omgdi:waypoint x=\"1080.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"1140.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flowLargeRejected\" id=\"BPMNEdge_flowLargeRejected\">\n          <omgdi:waypoint x=\"1060.0\" y=\"295.0\"/>\n          <omgdi:waypoint x=\"1060.0\" y=\"150.0\"/>\n          <omgdi:waypoint x=\"1000.0\" y=\"150.0\"/>\n          <omgdi:waypoint x=\"1000.0\" y=\"124.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow10\" id=\"BPMNEdge_flow10\">\n          <omgdi:waypoint x=\"1240.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"1280.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n        <bpmndi:BPMNEdge bpmnElement=\"flow11\" id=\"BPMNEdge_flow11\">\n          <omgdi:waypoint x=\"1380.0\" y=\"315.0\"/>\n          <omgdi:waypoint x=\"1430.0\" y=\"315.0\"/>\n        </bpmndi:BPMNEdge>\n      </bpmndi:BPMNPlane>\n    </bpmndi:BPMNDiagram>\n</definitions>\n','DEPLOYED','DEMO'),
	(6,'2026-03-05 04:42:17.184859',b'0','ORGANIZATION','df_org_uid','BYTEDESK','df_org_uid_itSupportProcess','2026-03-05 04:42:17.265467',NULL,1,'b024b502-184d-11f1-9a31-e2a00dfcd8a4','IT支持流程','IT支持流程','<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<definitions xmlns=\"http://www.omg.org/spec/BPMN/20100524/MODEL\"\n             xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\n             xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\"\n             xmlns:flowable=\"http://flowable.org/bpmn\"\n             xmlns:bpmndi=\"http://www.omg.org/spec/BPMN/20100524/DI\"\n             xmlns:omgdc=\"http://www.omg.org/spec/DD/20100524/DC\"\n             xmlns:omgdi=\"http://www.omg.org/spec/DD/20100524/DI\"\n             typeLanguage=\"http://www.w3.org/2001/XMLSchema\"\n             expressionLanguage=\"http://www.w3.org/1999/XPath\"\n             targetNamespace=\"BytedeskITSupport\">\n  <process id=\"itSupportProcess\" name=\"IT支持流程\" isExecutable=\"true\">\n    <extensionElements>\n      <flowable:executionListener event=\"start\" delegateExpression=\"${demoExecutionListener}\"/>\n      <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n    </extensionElements>\n\n    <!-- 开始事件 -->\n    <startEvent id=\"start\" name=\"提交工单\"/>\n\n    <!-- 提交IT工单 -->\n    <userTask id=\"submitTicket\" name=\"提交IT工单\" flowable:assignee=\"${requesterUid}\">\n      <documentation>用户填写IT工单，包括问题描述、优先级、附件</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <sequenceFlow id=\"flow1\" sourceRef=\"start\" targetRef=\"submitTicket\"/>\n\n    <!-- 工单分类网关 -->\n    <exclusiveGateway id=\"categoryGateway\" name=\"工单分类\"/>\n\n    <sequenceFlow id=\"flow2\" sourceRef=\"submitTicket\" targetRef=\"categoryGateway\"/>\n\n    <!-- 硬件问题 -->\n    <sequenceFlow id=\"flowHardware\" name=\"硬件问题\" sourceRef=\"categoryGateway\" targetRef=\"hardwareSupport\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${category == \'HARDWARE\'}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"hardwareSupport\" name=\"硬件支持\" flowable:candidateGroups=\"${hardwareGroupId}\">\n      <documentation>IT硬件团队处理硬件相关问题</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 软件问题 -->\n    <sequenceFlow id=\"flowSoftware\" name=\"软件问题\" sourceRef=\"categoryGateway\" targetRef=\"softwareSupport\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${category == \'SOFTWARE\'}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"softwareSupport\" name=\"软件支持\" flowable:candidateGroups=\"${softwareGroupId}\">\n      <documentation>IT软件团队处理软件相关问题</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 网络问题 -->\n    <sequenceFlow id=\"flowNetwork\" name=\"网络问题\" sourceRef=\"categoryGateway\" targetRef=\"networkSupport\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${category == \'NETWORK\'}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"networkSupport\" name=\"网络支持\" flowable:candidateGroups=\"${networkGroupId}\">\n      <documentation>IT网络团队处理网络相关问题</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 账号权限问题 -->\n    <sequenceFlow id=\"flowAccount\" name=\"账号权限\" sourceRef=\"categoryGateway\" targetRef=\"accountSupport\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${category == \'ACCOUNT\'}</conditionExpression>\n    </sequenceFlow>\n\n    <serviceTask id=\"accountSupport\" name=\"自动账号处理\" flowable:delegateExpression=\"${demoAccountDelegate}\">\n      <documentation>自动处理账号权限相关问题</documentation>\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n      </extensionElements>\n    </serviceTask>\n\n    <sequenceFlow id=\"flowAccountComplete\" sourceRef=\"accountSupport\" targetRef=\"verify\"/>\n\n    <!-- 优先级判断网关 -->\n    <exclusiveGateway id=\"priorityGateway\" name=\"判断优先级\"/>\n\n    <sequenceFlow id=\"flowHardwareToPriority\" sourceRef=\"hardwareSupport\" targetRef=\"priorityGateway\"/>\n    <sequenceFlow id=\"flowSoftwareToPriority\" sourceRef=\"softwareSupport\" targetRef=\"priorityGateway\"/>\n    <sequenceFlow id=\"flowNetworkToPriority\" sourceRef=\"networkSupport\" targetRef=\"priorityGateway\"/>\n\n    <!-- 高优先级：需要升级 -->\n    <sequenceFlow id=\"flowHighPriority\" name=\"高优先级\" sourceRef=\"priorityGateway\" targetRef=\"escalate\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${priority == \'HIGH\' || priority == \'URGENT\'}</conditionExpression>\n    </sequenceFlow>\n\n    <userTask id=\"escalate\" name=\"升级处理\" flowable:candidateGroups=\"${itManagerGroupId}\">\n      <documentation>IT经理处理高优先级问题</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"assignment\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n        <!-- 高优先级任务超时定时器：1小时 -->\n      </extensionElements>\n    </userTask>\n\n    <!-- 高优先级超时定时器 -->\n    <boundaryEvent id=\"escalateTimeout\" cancelActivity=\"false\" attachedToRef=\"escalate\">\n      <timerEventDefinition>\n        <timeDuration>PT1H</timeDuration>\n      </timerEventDefinition>\n    </boundaryEvent>\n\n    <serviceTask id=\"escalateTimeoutNotify\" name=\"超时升级通知\" flowable:delegateExpression=\"${demoEscalationNotifyDelegate}\"/>\n\n    <sequenceFlow id=\"flowEscalateTimeout\" sourceRef=\"escalateTimeout\" targetRef=\"escalateTimeoutNotify\"/>\n\n    <sequenceFlow id=\"flowEscalateTimeoutNotify\" sourceRef=\"escalateTimeoutNotify\" targetRef=\"notifyEnd\"/>\n\n    <sequenceFlow id=\"flowEscalateToVerify\" sourceRef=\"escalate\" targetRef=\"verify\"/>\n\n    <!-- 普通优先级：直接验证 -->\n    <sequenceFlow id=\"flowNormalPriority\" name=\"普通优先级\" sourceRef=\"priorityGateway\" targetRef=\"verify\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${priority == \'NORMAL\' || priority == \'LOW\'}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- SLA超时定时器（针对所有支持任务） -->\n    <boundaryEvent id=\"slaTimeout\" cancelActivity=\"false\" attachedToRef=\"hardwareSupport\">\n      <timerEventDefinition>\n        <timeDuration>${slaTimeISO != null ? slaTimeISO : \'PT4H\'}</timeDuration>\n      </timerEventDefinition>\n    </boundaryEvent>\n\n    <serviceTask id=\"slaTimeoutNotify\" name=\"SLA超时通知\" flowable:delegateExpression=\"${demoSlaTimeoutNotifyDelegate}\"/>\n\n    <sequenceFlow id=\"flowSlaTimeout\" sourceRef=\"slaTimeout\" targetRef=\"slaTimeoutNotify\"/>\n\n    <sequenceFlow id=\"flowSlaTimeoutNotify\" sourceRef=\"slaTimeoutNotify\" targetRef=\"hardwareSupport\"/>\n\n    <!-- 用户验证 -->\n    <userTask id=\"verify\" name=\"用户验证\" flowable:assignee=\"${requesterUid}\">\n      <documentation>用户验证问题是否已解决</documentation>\n      <extensionElements>\n        <flowable:taskListener event=\"create\" delegateExpression=\"${demoTaskListener}\"/>\n        <flowable:taskListener event=\"complete\" delegateExpression=\"${demoTaskListener}\"/>\n      </extensionElements>\n    </userTask>\n\n    <!-- 验证结果网关 -->\n    <exclusiveGateway id=\"verifyResultGateway\" name=\"验证结果\"/>\n\n    <sequenceFlow id=\"flowVerify\" sourceRef=\"verify\" targetRef=\"verifyResultGateway\"/>\n\n    <!-- 已解决 -->\n    <sequenceFlow id=\"flowSolved\" name=\"已解决\" sourceRef=\"verifyResultGateway\" targetRef=\"closeTicket\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${solved == true}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 未解决：重新处理 -->\n    <sequenceFlow id=\"flowNotSolved\" name=\"未解决\" sourceRef=\"verifyResultGateway\" targetRef=\"categoryGateway\">\n      <conditionExpression xsi:type=\"tFormalExpression\">${solved == false}</conditionExpression>\n    </sequenceFlow>\n\n    <!-- 关闭工单 -->\n    <serviceTask id=\"closeTicket\" name=\"关闭工单\" flowable:delegateExpression=\"${demoCloseTicketDelegate}\">\n      <documentation>关闭工单并发送满意度调查</documentation>\n      <extensionElements>\n        <flowable:executionListener event=\"end\" delegateExpression=\"${demoExecutionListener}\"/>\n      </extensionElements>\n    </serviceTask>\n\n    <sequenceFlow id=\"flowClose\" sourceRef=\"closeTicket\" targetRef=\"end\"/>\n\n    <!-- 满意度调查 -->\n    <serviceTask id=\"satisfactionSurvey\" name=\"满意度调查\" flowable:delegateExpression=\"${demoSatisfactionDelegate}\">\n      <documentation>发送满意度调查问卷</documentation>\n    </serviceTask>\n\n    <sequenceFlow id=\"flowSurvey\" sourceRef=\"end\" targetRef=\"satisfactionSurvey\"/>\n\n    <!-- 结束事件 -->\n    <endEvent id=\"end\" name=\"流程结束\"/>\n\n    <!-- 升级通知结束事件 -->\n    <endEvent id=\"notifyEnd\" name=\"发送升级通知结束\"/>\n  </process>\n\n  <!-- 流程图布局 -->\n  <bpmndi:BPMNDiagram id=\"BPMNDiagram_itSupportProcess\">\n      <bpmndi:BPMNPlane bpmnElement=\"itSupportProcess\" id=\"BPMNPlane_itSupportProcess\">\n        <bpmndi:BPMNShape bpmnElement=\"start\" id=\"BPMNShape_start\">\n          <omgdc:Bounds height=\"30.0\" width=\"30.0\" x=\"100.0\" y=\"300.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"submitTicket\" id=\"BPMNShape_submitTicket\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"180.0\" y=\"285.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"categoryGateway\" id=\"BPMNShape_categoryGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"330.0\" y=\"295.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"hardwareSupport\" id=\"BPMNShape_hardwareSupport\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"150.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"softwareSupport\" id=\"BPMNShape_softwareSupport\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"240.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"networkSupport\" id=\"BPMNShape_networkSupport\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"330.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"accountSupport\" id=\"BPMNShape_accountSupport\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"430.0\" y=\"420.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"priorityGateway\" id=\"BPMNShape_priorityGateway\">\n          <omgdc:Bounds height=\"40.0\" width=\"40.0\" x=\"590.0\" y=\"235.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"escalate\" id=\"BPMNShape_escalate\">\n          <omgdc:Bounds height=\"60.0\" width=\"100.0\" x=\"700.0\" y=\"100.0\"/>\n        </bpmndi:BPMNShape>\n        <bpmndi:BPMNShape bpmnElement=\"verify\" id=\"BPMNShape_verify\">\n          <omgdc:Bounds h